import math
import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
sys.path.insert(0, str(ROOT / "backend"))

from reporting.content_credibility_evidence_confidence import evaluate_confidence_evidence_alignment  # noqa: E402
from reporting.content_credibility_inputs import confidence_score, first_price, target_price_candidates  # noqa: E402


def test_first_price_rejects_non_finite_numeric_tokens():
    assert first_price(float("nan")) is None
    assert first_price(float("inf")) is None
    assert first_price(float("-inf")) is None


def test_target_price_candidates_drop_non_finite_numeric_prices():
    candidates = target_price_candidates(
        {
            "price_targets": {
                "基本情境": float("nan"),
                "牛市情境": 120,
            }
        }
    )

    assert len(candidates) == 1
    assert candidates[0]["label"] == "牛市情境"
    assert math.isfinite(candidates[0]["price"])


def test_target_price_candidates_use_range_midpoint_after_percent_preface():
    for target_12m in ("上行60％，目標價100-160", "上行 6e1%，目標價100-160", "上行６０．５％，目標價100-160"):
        candidates = target_price_candidates({"recommendation": {"12個月": target_12m}})

        assert candidates[0]["source"] == "recommendation.12個月"
        assert candidates[0]["price"] == 130.0


def test_target_price_candidates_use_unit_suffixed_range_midpoint():
    candidates = target_price_candidates({"recommendation": {"12個月": "目標價100-160元"}})

    assert candidates[0]["source"] == "recommendation.12個月"
    assert candidates[0]["price"] == 130.0


def test_target_price_candidates_use_left_unit_range_midpoint():
    candidates = target_price_candidates({"recommendation": {"12個月": "目標價100元-160"}})

    assert candidates[0]["source"] == "recommendation.12個月"
    assert candidates[0]["price"] == 130.0


def test_target_price_candidates_use_right_currency_range_midpoint():
    candidates = target_price_candidates({"recommendation": {"12個月": "目標價100至NT$160"}})

    assert candidates[0]["source"] == "recommendation.12個月"
    assert candidates[0]["price"] == 130.0


def test_target_price_candidates_prefer_long_term_target_when_multiple_horizons_are_present():
    for target_12m in (
        "12個月目標價160元，6個月目標價140元",
        "6個月目標價140元，12個月目標價160元",
        "12M target price NT$160; 6M target price NT$140",
        "long-term target price NT$160; short-term target price NT$140",
    ):
        candidates = target_price_candidates({"recommendation": {"12個月": target_12m}})

        assert candidates[0]["source"] == "recommendation.12個月"
        assert candidates[0]["price"] == 160.0


def test_target_price_candidates_use_matching_horizon_for_each_recommendation_label():
    raw = "12個月目標價160元，6個月目標價140元，3個月目標價120元"

    candidates = target_price_candidates(
        {
            "recommendation": {
                "12個月": raw,
                "6個月": raw,
                "3個月": raw,
            }
        }
    )

    assert candidates == [
        {"source": "recommendation.12個月", "label": "12個月", "price": 160.0, "raw": raw},
        {"source": "recommendation.6個月", "label": "6個月", "price": 140.0, "raw": raw},
        {"source": "recommendation.3個月", "label": "3個月", "price": 120.0, "raw": raw},
    ]


def test_target_price_candidates_ignore_period_prefix_before_target_range():
    for target_12m in ("12個月目標價 100-160", "未來12個月目標價100-160", "2027年目標價100-160", "12M target 100-160"):
        candidates = target_price_candidates({"recommendation": {"12個月": target_12m}})

        assert candidates[0]["source"] == "recommendation.12個月"
        assert candidates[0]["price"] == 130.0


def test_target_price_candidates_use_english_to_range_midpoint():
    for target_12m in (
        "12M target price 100 to 160",
        "target price range 100 to 160",
        "price target 100 to NT$160",
        "12M target between 100 and 160",
        "target price between 100 and 160",
    ):
        candidates = target_price_candidates({"recommendation": {"12個月": target_12m}})

        assert candidates[0]["source"] == "recommendation.12個月"
        assert candidates[0]["price"] == 130.0


def test_target_price_candidates_use_between_range_midpoint():
    for target_12m in ("target price between 100 and 160", "12M target between 100 and 160", "目標價介於100與160元", "合理價落在100與160元之間"):
        candidates = target_price_candidates({"recommendation": {"12個月": target_12m}})

        assert candidates[0]["source"] == "recommendation.12個月"
        assert candidates[0]["price"] == 130.0


def test_target_price_candidates_ignore_macro_inflation_and_yield_curve_targets():
    context = {
        "recommendation": {
            "12個月": "target price NT$160 with CPI target 2",
            "6個月": "yield curve target 100",
            "3個月": "消費者物價指數目標2",
        },
        "price_targets": {
            "基本情境": "target price NT$160 with inflation target 2",
            "牛市情境": "inflation rate target 2",
            "熊市情境": "CPI target 2",
        },
    }

    candidates = target_price_candidates(context)

    assert candidates == [
        {"source": "recommendation.12個月", "label": "12個月", "price": 160.0, "raw": "target price NT$160 with CPI target 2"},
        {"source": "price_targets.基本情境", "label": "基本情境", "price": 160.0, "raw": "target price NT$160 with inflation target 2"},
    ]


