def test_denominator_prefaced_confidence_score_uses_given_score_for_evidence_alignment():
    low_score = confidence_score({"信心指數": "滿分10分，信心5分"})
    low_result = evaluate_confidence_evidence_alignment("rejected", low_score)
    high_score = confidence_score({"信心指數": "滿分10分，信心8分"})
