def test_ratio_confidence_score_uses_denominator_for_evidence_alignment():
    low_score = confidence_score({"信心指數": "5/100"})
    high_score = confidence_score({"信心指數": "60／100"})
    chinese_decimal_score = confidence_score({"信心指數": "6點5/10"})
    fullwidth_chinese_decimal_score = confidence_score({"信心指數": "６點５／１０"})
    five_point_score = confidence_score({"信心指數": "4 out of 5"})
    five_point_result = evaluate_confidence_evidence_alignment("rejected", five_point_score)
    five_star_score = confidence_score({"信心指數": "4星/5星"})
    half_star_score = confidence_score({"信心指數": "4星半/5星"})
    chinese_five_point_score = confidence_score({"信心指數": "四分滿分五分"})
    chinese_five_star_score = confidence_score({"信心指數": "四星/五星"})
    chinese_half_star_score = confidence_score({"信心指數": "四星半/五星"})
    chinese_half_point_score = confidence_score({"信心指數": "四分半滿分五分"})
    denominator_first_chinese_score = confidence_score({"信心指數": "五分之四"})
    denominator_first_digit_score = confidence_score({"信心指數": "5分之4"})
    five_point_scale_score = confidence_score({"信心指數": "5分制4.5分"})
    chinese_five_point_scale_score = confidence_score({"信心指數": "五分制四點五分"})
    chinese_star_scale_score = confidence_score({"信心指數": "五顆星給四顆半"})

    assert low_score == 0.5
    assert high_score == 6.0
    assert chinese_decimal_score == 6.5
    assert fullwidth_chinese_decimal_score == 6.5
    assert five_point_score == 8.0
    assert five_point_result["blocking_issues"][0]["id"] == "high_confidence_rejected_evidence"
    assert five_star_score == 8.0
    assert half_star_score == 9.0
    assert chinese_five_point_score == 8.0
    assert chinese_five_star_score == 8.0
    assert chinese_half_star_score == 9.0
    assert chinese_half_point_score == 9.0
    assert denominator_first_chinese_score == 8.0
    assert denominator_first_digit_score == 8.0
    assert five_point_scale_score == 9.0
    assert chinese_five_point_scale_score == 9.0
    assert chinese_star_scale_score == 9.0


def test_ratio_confidence_score_is_capped_to_ten_for_evidence_alignment():
    assert confidence_score({"信心指數": "12/10"}) == 10.0
