def test_denominator_prefaced_confidence_score_is_scaled_for_evidence_alignment():
    low_score = confidence_score({"信心指數": "信心十分之五點五"})
    numeric_low_score = confidence_score({"信心指數": "信心10分之5.5"})
    percent_low_score = confidence_score({"信心指數": "信心百分之五十五"})
    threshold_score = confidence_score({"信心指數": "信心十分之六點五"})
    high_score = confidence_score({"信心指數": "信心百分之八十五"})
    perfect_percent_score = confidence_score({"信心指數": "信心百分之百"})
    explicit_perfect_percent_score = confidence_score({"信心指數": "信心百分之一百"})
    colloquial_perfect_percent_score = confidence_score({"信心指數": "信心百分百"})
    capped_percent_score = confidence_score({"信心指數": "信心百分之一百二十"})
    high_result = evaluate_confidence_evidence_alignment("rejected", high_score)

    assert low_score == 5.5
    assert numeric_low_score == 5.5
    assert percent_low_score == 5.5
    assert threshold_score == 6.5
    assert high_score == 8.5
    assert perfect_percent_score == 10.0
    assert explicit_perfect_percent_score == 10.0
    assert colloquial_perfect_percent_score == 10.0
    assert capped_percent_score == 10.0
    assert high_result["blocking_issues"][0]["id"] == "high_confidence_rejected_evidence"


def test_low_percent_confidence_score_is_scaled_for_evidence_alignment():
    low_score = confidence_score({"信心指數": "5％"})
    fractional_percent_score = confidence_score({"信心指數": "０．５％"})
    chinese_decimal_percent_score = confidence_score({"信心指數": "55點5%"})
