    terms = ("certificate", "closure", "exception", "corrective action")
    selected_targets = tuple(
        f"contamination readiness {' '.join(combo)} queue items target 160"
        for size in (2, 3, 4)
        for combo in permutations(terms, size)
    )[:20]
    targets = {
        f"ContaminationReadinessServiceQueue{index}情境": raw
        for index, raw in enumerate(selected_targets, start=1)
    }
    valid_cases = {
        label.replace("情境", "有效情境"): f"target price NT$160 with {raw}"
        for label, raw in targets.items()
    }

    candidates = target_price_candidates({"price_targets": {**targets, **valid_cases}})

    assert candidates == [
        {
            "source": f"price_targets.{label}",
            "label": label,
            "price": 160.0,
            "raw": raw,
        }
        for label, raw in valid_cases.items()
    ]


